// Pega contexto da loja atual
const lojaContext = $('Loop Lojas').item.json;
const EMPRESA_ID = lojaContext.empresa_id;
const LOJA_ID = lojaContext.loja_id;
const CODIGO_LOJA = lojaContext.codigo_loja;

const content = $input.first().json.content;

if (!content || !Array.isArray(content)) {
  return [];
}

// Espécies fiscais válidas
const ESPECIES_FISCAIS = ['NF', 'IF', 'FF'];

// Map para deduplicar por numero_faturamento
const faturamentos = new Map();

for (const doc of content) {
  if (!doc.jaFaturado) continue;

  const itens = doc.itens || [];

  for (const item of itens) {
    const numeroFaturamento = item.numeroFaturamento?.replace(/^0+/, '');
    const especieFaturamento = item.especieFaturamento;
    const dataFaturamento = item.dataFaturamento;

    // Filtrar apenas documentos fiscais válidos
    if (!numeroFaturamento || !especieFaturamento) continue;
    if (!ESPECIES_FISCAIS.includes(especieFaturamento)) continue;
    if (!dataFaturamento) continue;

    const key = `${CODIGO_LOJA}-${especieFaturamento}-${numeroFaturamento}`;

    if (!faturamentos.has(key)) {
      // valor_contabil é o valor total do faturamento (pegar apenas uma vez, não somar)
      const valorContabil = doc.valorContabil || doc.valorContabil || 0;

      faturamentos.set(key, {
        empresa_id: EMPRESA_ID,
        loja_id: LOJA_ID,
        codigo_loja: CODIGO_LOJA,
        numero_faturamento: numeroFaturamento,
        especie_faturamento: especieFaturamento,
        data_faturamento: dataFaturamento,

        // Origem
        numero_documento_origem: doc.numeroDocumento?.replace(/^0+/, '') || null,
        especie_documento_origem: doc.especieDocumento || null,
        data_entrada_origem: doc.dataEntrada || null,

        // Vendedor
        codigo_vendedor: doc.codigoVendedor || null,
        nome_vendedor: doc.nomeVendedor || null,

        // Cliente
        codigo_cliente: doc.cliente?.codigoCliente?.replace(/^0+/, '') || null,
        nome_cliente: doc.cliente?.nome || doc.nomeConsumidorOuCliente || null,

        // Valor total do faturamento (não acumula)
        valor_contabil: valorContabil,
        valor_total_itens: 0,
        valor_frete: 0,
        quantidade_itens: 0
      });
    }

    // Acumular apenas contagem de itens e frete (valor_contabil não é mais somado)
    const fat = faturamentos.get(key);
    fat.valor_total_itens += item.totalItem || 0;
    fat.valor_frete += item.totalFrete || 0;
    fat.quantidade_itens += 1;
  }
}

// Converter Map para Array de items
return Array.from(faturamentos.values()).map(fat => ({
  json: {
    ...fat,
    valor_contabil: Number(fat.valor_contabil.toFixed(2)),
    valor_total_itens: Number(fat.valor_total_itens.toFixed(2)),
    valor_frete: Number(fat.valor_frete.toFixed(2))
  }
}));

